// BuildFeedbackEmail constructs an HTML-formatted email for user feedback
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate input parameters
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("sender and recipient addresses are required")
	}
	if userName == "" || subject == "" || feedbackContent == "" {
		return "", fmt.Errorf("all feedback fields are required")
	}

	// Escape HTML special characters to prevent injection
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedContent := html.EscapeString(feedbackContent)

	// Encode subject for email headers (handles special characters)
	encodedSubject := mime.QEncoding.Encode("UTF-8", subject)

	// Build email headers
	headers := make(map[string]string)
	headers["From"] = fromAddr
	headers["To"] = toAddr
	headers["Subject"] = encodedSubject
	headers["MIME-Version"] = "1.0"
	headers["Content-Type"] = "text/html; charset=UTF-8"
	headers["Content-Transfer-Encoding"] = "quoted-printable"

	// Build HTML email body
	htmlBody := fmt.Sprintf(`
<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <style>
        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
        .container { max-width: 600px; margin: 0 auto; padding: 20px; }
        .header { background-color: #f8f9fa; padding: 15px; border-radius: 5px; }
        .content { background-color: #ffffff; padding: 20px; border: 1px solid #dee2e6; border-radius: 5px; margin-top: 20px; }
        .field { margin-bottom: 15px; }
        .label { font-weight: bold; color: #495057; }
        .value { margin-top: 5px; padding: 10px; background-color: #f8f9fa; border-radius: 3px; }
        .footer { margin-top: 20px; font-size: 12px; color: #6c757d; text-align: center; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h2>📨 New User Feedback Received</h2>
        </div>
        <div class="content">
            <div class="field">
                <div class="label">👤 User Name:</div>
                <div class="value">%s</div>
            </div>
            <div class="field">
                <div class="label">📋 Feedback Subject:</div>
                <div class="value">%s</div>
            </div>
            <div class="field">
                <div class="label">💬 Feedback Content:</div>
                <div class="value">%s</div>
            </div>
        </div>
        <div class="footer">
            <p>This email was automatically generated by the feedback system.</p>
            <p>Timestamp: %s</p>
        </div>
    </div>
</body>
</html>`, escapedUserName, escapedSubject, strings.ReplaceAll(escapedContent, "\n", "<br>"), getCurrentTimestamp())

	// Build complete email message
	var msg bytes.Buffer
