		msg.WriteString(fmt.Sprintf("%s: %s\r\n", key, value))
	}
	msg.WriteString("\r\n") // Empty line separates headers from body
	msg.WriteString(htmlBody)

	return msg.String(), nil
}

// Helper function to get current timestamp (simplified version)
func getCurrentTimestamp() string {
	// In a real implementation, you would use time.Now().Format(time.RFC3339)
	return "2023-10-05 14:30:00 UTC"
}

// Example usage and SMTP sending function
func main() {
	// Example data
	from := "system@example.com"
	to := "support@example.com"
	userName := "John Doe"
	subject := "Bug Report: Login Issue"
	feedbackContent := `Hello,

I'm experiencing an issue when trying to log in to the application. 
After entering my credentials, I get an "Internal Server Error" message.

Steps to reproduce:
1. Go to login page
2. Enter email and password
3. Click "Sign In"
4. Error appears immediately

This started happening after the latest update. Please fix this soon as it's blocking my work.

Best regards,
John`

	// Build the email
	emailBody, err := BuildFeedbackEmail(from, to, userName, subject, feedbackContent)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println("✅ Email built successfully!")
	fmt.Println("\n--- Email Preview ---")
	fmt.Println(emailBody)

	// Uncomment to actually send the email using SMTP
	// sendEmail(emailBody, from, to, "smtp.example.com:587", "username", "password")
}

// Helper function to send email via SMTP
func sendEmail(emailBody, from, to, smtpServer, username, password string) error {
	// Split smtpServer into host and port
	hostPort := strings.Split(smtpServer, ":")
	if len(hostPort) != 2 {
		return fmt.Errorf("invalid SMTP server address")
	}

	// Set up authentication
	auth := smtp.PlainAuth("", username, password, hostPort[0])

	// Send email
	err := smtp.SendMail(
		smtpServer,
		auth,
		from,
		[]string{to},
		[]byte(emailBody),
	)

	if err != nil {
		return fmt.Errorf("failed to send email: %v", err)
	}

	fmt.Println("📧 Email sent successfully!")
	return nil
}

