package main

import (
	"fmt"
	"net/mail"
	"net/smtp"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (optional but good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Construct email headers
	emailSubject := fmt.Sprintf("Feedback: %s", subject)

	// Use proper MIME encoding for subject to handle non-ASCII characters
	encodedSubject := mimeQEncoding(emailSubject)

	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		encodedSubject,
	)

	// Construct HTML body with proper escaping
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		escapeHTML(userName),
		escapeHTML(subject),
		escapeHTML(feedbackContent),
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

// mimeQEncoding encodes a string using MIME Q-encoding for email headers
func mimeQEncoding(input string) string {
	var result strings.Builder
	for _, r := range input {
		if r >= 33 && r <= 126 && r != '?' && r != '=' && r != '_' {
			result.WriteRune(r)
		} else {
			result.WriteString(fmt.Sprintf("=%02X", r))
		}
	}

	// If the string contains non-ASCII or special characters, wrap in encoded-word format
	if strings.ContainsAny(input, "=?") || !isASCII(input) {
		return fmt.Sprintf("=?UTF-8?Q?%s?=", result.String())
	}
	return input
}

// isASCII checks if a string contains only ASCII characters
func isASCII(s string) bool {
	for _, r := range s {
		if r > 127 {
			return false
		}
	}
	return true
}

// escapeHTML escapes HTML special characters to prevent XSS
func escapeHTML(input string) string {
	return strings.NewReplacer(
		"&", "&amp;",
		"<", "&lt;",
		">", "&gt;",
		"\"", "&quot;",
		"'", "&#39;",
	).Replace(input)
}

// Helper function to send the email using smtp.SendMail
func SendFeedbackEmail(smtpHost string, smtpPort string, auth smtp.Auth, fromAddr string, toAddr string, userName string, subject string, feedbackContent string) error {
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		return fmt.Errorf("failed to build email: %w", err)
	}

	// Convert to []byte for smtp.SendMail
	msg := []byte(emailBody)

	// Send the email
	err = smtp.SendMail(
		fmt.Sprintf("%s:%s", smtpHost, smtpPort),
		auth,
		fromAddr,
		[]string{toAddr},
		msg,
	)

	if err != nil {
		return fmt.Errorf("failed to send email: %w", err)
	}

	return nil
}

