package main

import (
	"fmt"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (optional but good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Escape HTML special characters to prevent injection
	escapedUserName := htmlEscape(userName)
	escapedSubject := htmlEscape(subject)
	escapedContent := htmlEscape(feedbackContent)

	// Construct email headers with proper MIME encoding for subject
	emailSubject := fmt.Sprintf("Feedback: %s", escapedSubject)
	encodedSubject := mimeEncode(emailSubject)

	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		encodedSubject,
	)

	// Construct HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd; white-space: pre-wrap; word-wrap: break-word;">%s</pre>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedContent,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

// htmlEscape escapes HTML special characters to prevent injection
func htmlEscape(s string) string {
	return strings.NewReplacer(
		"&", "&amp;",
		"<", "&lt;",
		">", "&gt;",
		"\"", "&quot;",
		"'", "&#39;",
	).Replace(s)
}

// mimeEncode encodes non-ASCII characters in subject using MIME encoding
func mimeEncode(s string) string {
	var result strings.Builder
	for _, r := range s {
		if r > 127 {
			// Encode non-ASCII characters
			result.WriteString(fmt.Sprintf("=?UTF-8?q?%s?=", qEncode(string(r))))
		} else {
			result.WriteRune(r)
		}
	}
	return result.String()
}

// qEncode encodes a single character for quoted-printable encoding
func qEncode(s string) string {
	if len(s) == 0 {
		return ""
	}
	return fmt.Sprintf("=%02X", []byte(s)[0])
}

