	}

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

// sanitizeHeader removes dangerous characters that could lead to email header injection
func sanitizeHeader(input string) string {
	// Remove newlines and carriage returns that could break email headers
	input = strings.ReplaceAll(input, "\r", "")
	input = strings.ReplaceAll(input, "\n", "")
	input = strings.ReplaceAll(input, "\t", "")

	// Remove potentially dangerous characters
	dangerousChars := []string{":", ";", "<", ">", "\"", "'", "\\", "/", "[", "]"}
	for _, char := range dangerousChars {
		input = strings.ReplaceAll(input, char, "")
	}

	return strings.TrimSpace(input)
}

// mimeEncode encodes non-ASCII characters in email headers
func mimeEncode(text string) string {
	// Simple implementation - for production use proper MIME encoding library
	// This handles basic cases where subject contains only ASCII
	if isASCII(text) {
		return text
	}

	// For non-ASCII, we'd use proper encoding like RFC 2047
	// For simplicity in this example, we'll return as-is with warning
	// In production, use: mime.QEncoding.Encode("utf-8", text)
	return text
}

func isASCII(s string) bool {
	for _, c := range s {
		if c > 127 {
			return false
		}
	}
	return true
}

// generateHTMLBody creates HTML email body with proper escaping
func generateHTMLBody(userName, subject, feedbackContent string) (string, error) {
	// Define HTML template with proper escaping
	const htmlTemplate = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
  <style>
    body { font-family: Arial, sans-serif; margin: 20px; }
    .container { max-width: 600px; margin: 0 auto; }
    .header { background-color: #f8f9fa; padding: 20px; border-radius: 5px; }
    .content { margin: 20px 0; }
    .feedback-box { 
      background-color: #f9f9f9; 
      padding: 15px; 
      border: 1px solid #ddd; 
      border-radius: 4px;
      white-space: pre-wrap;
      word-wrap: break-word;
    }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h2>User Feedback Received</h2>
    </div>
    <div class="content">
      <p><strong>Submitted by:</strong> {{.UserName}}</p>
      <p><strong>Subject:</strong> {{.Subject}}</p>
      <div>
        <strong>Message:</strong><br>
        <div class="feedback-box">{{.FeedbackContent}}</div>
      </div>
    </div>
  </div>
</body>
</html>`

	// Create template with auto-escaping
	tmpl, err := template.New("email").Parse(htmlTemplate)
	if err != nil {
		return "", err
	}

	// Prepare data with sanitized inputs
	data := struct {
		UserName        string
		Subject         string
		FeedbackContent string
	}{
		UserName:        template.HTMLEscapeString(userName),
		Subject:         template.HTMLEscapeString(subject),
		FeedbackContent: template.HTMLEscapeString(feedbackContent),
	}

	// Execute template
	var buf bytes.Buffer
	if err := tmpl.Execute(&buf, data); err != nil {
		return "", err
	}

	return buf.String(), nil
}

// Helper function to send email using smtp package
func SendFeedbackEmail(smtpHost string, smtpPort int, username, password string, emailBody string) error {
	// This is a helper function to demonstrate sending the email
	auth := smtp.PlainAuth("", username, password, smtpHost)

	// Parse From and To addresses from email body
	lines := strings.Split(emailBody, "\r\n")
	var from, to string
	for _, line := range lines {
		if strings.HasPrefix(line, "From: ") {
			from = strings.TrimPrefix(line, "From: ")
		}
		if strings.HasPrefix(line, "To: ") {
			to = strings.TrimPrefix(line, "To: ")
		}
		if from != "" && to != "" {
			break
		}
	}

	toAddresses := []string{to}

	// Send email
	err := smtp.SendMail(
		fmt.Sprintf("%s:%d", smtpHost, smtpPort),
		auth,
		from,
		toAddresses,
		[]byte(emailBody),
	)

	return err
}

