// SendEmail sends the generated email using SMTP
func SendEmail(smtpHost string, smtpPort string, username string, password string, emailBody string) error {
	// Parse the email body to extract recipients
	lines := strings.Split(emailBody, "\n")
	var toAddr string

	for _, line := range lines {
		if strings.HasPrefix(line, "To: ") {
			toAddr = strings.TrimPrefix(line, "To: ")
			break
		}
	}

	if toAddr == "" {
		return fmt.Errorf("no recipient found in email body")
	}

	// Connect to SMTP server
	auth := smtp.PlainAuth("", username, password, smtpHost)
	addr := fmt.Sprintf("%s:%s", smtpHost, smtpPort)

	// Send the email
	err := smtp.SendMail(addr, auth, username, []string{toAddr}, []byte(emailBody))
	if err != nil {
		return fmt.Errorf("failed to send email: %v", err)
	}

	return nil
}

