  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h2 style="margin: 0; color: #212529;">User Feedback Received</h2>
    </div>
    <div class="content">
      <p><span class="label">Submitted by:</span> %s</p>
      <p><span class="label">Subject:</span> %s</p>
      <div>
        <span class="label">Message:</span>
        <div class="feedback-box">%s</div>
      </div>
    </div>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedbackContent,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

