// BuildFeedbackEmail constructs an HTML-formatted email containing user feedback
// Parameters:
//   - fromAddr: sender email address
//   - toAddr: recipient email address (customer support)
//   - userName: name of the user submitting feedback
//   - subject: feedback subject/title
//   - feedbackContent: detailed feedback content
//
// Returns:
//   - emailBody: complete SMTP-ready email message
//   - err: error if any occurred during construction
func BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent string) (emailBody string, err error) {
	// Validate required parameters
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("from and to addresses are required")
	}
	if userName == "" || subject == "" || feedbackContent == "" {
		return "", fmt.Errorf("all feedback fields must be provided")
	}

	// Generate unique message ID
	messageID := fmt.Sprintf("%d.%s@feedback.system", time.Now().UnixNano(), strings.Split(fromAddr, "@")[0])

	// Create email headers
	headers := make(map[string]string)
	headers["From"] = mime.QEncoding.Encode("utf-8", "Feedback System") + " <" + fromAddr + ">"
	headers["To"] = toAddr
	headers["Subject"] = mime.QEncoding.Encode("utf-8", "User Feedback: "+subject)
	headers["Message-ID"] = "<" + messageID + ">"
	headers["Date"] = time.Now().Format(time.RFC1123Z)
	headers["MIME-Version"] = "1.0"
	headers["Content-Type"] = "text/html; charset=\"utf-8\""
	headers["Content-Transfer-Encoding"] = "quoted-printable"

	// Build HTML email body with user feedback
