    </div>

    <div class="feedback-section">
        <div class="field">
            <span class="field-label">Submitted By:</span>
            <div class="field-value">`)

	// Safely escape user input for HTML
	bodyBuffer.WriteString(escapeHTML(userName))
	bodyBuffer.WriteString(`</div>
