func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate email addresses
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid sender email: %v", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid recipient email: %v", err)
	}

	// Validate input parameters
	if strings.TrimSpace(userName) == "" {
		return "", fmt.Errorf("username cannot be empty")
	}
	if strings.TrimSpace(subject) == "" {
		return "", fmt.Errorf("subject cannot be empty")
	}
	if strings.TrimSpace(feedbackContent) == "" {
		return "", fmt.Errorf("feedback content cannot be empty")
	}

	// Prepare email headers
	headers := make(map[string]string)
	headers["From"] = fromAddr
	headers["To"] = toAddr
	headers["Subject"] = fmt.Sprintf("User Feedback: %s", subject)
	headers["MIME-Version"] = "1.0"
	headers["Content-Type"] = "text/html; charset=UTF-8"
	headers["Date"] = time.Now().Format(time.RFC1123Z)

	// Build HTML email body
	htmlBody, err := buildHTMLBody(userName, subject, feedbackContent)
	if err != nil {
		return "", fmt.Errorf("failed to build HTML body: %v", err)
	}

	// Construct complete email
	var buf bytes.Buffer
	for k, v := range headers {
		buf.WriteString(fmt.Sprintf("%s: %s\r\n", k, v))
	}
	buf.WriteString("\r\n")
	buf.WriteString(htmlBody)

	return buf.String(), nil
}

