	qpWriter := quotedprintable.NewWriter(&htmlEncoded)
	if _, err := qpWriter.Write([]byte(htmlBody)); err != nil {
		return "", fmt.Errorf("failed to encode HTML body: %w", err)
	}
	if err := qpWriter.Close(); err != nil {
		return "", fmt.Errorf("failed to close quoted-printable writer: %w", err)
	}

	// Construct the complete MIME message
	var emailBuilder strings.Builder
	emailBuilder.WriteString(headers)

	// Plain text part
	emailBuilder.WriteString(fmt.Sprintf("--%s\r\n", boundary))
	emailBuilder.WriteString("Content-Type: text/plain; charset=UTF-8\r\n")
	emailBuilder.WriteString("Content-Transfer-Encoding: 7bit\r\n\r\n")
	emailBuilder.WriteString(plainTextBody)
	emailBuilder.WriteString("\r\n")

	// HTML part
	emailBuilder.WriteString(fmt.Sprintf("--%s\r\n", boundary))
	emailBuilder.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	emailBuilder.WriteString("Content-Transfer-Encoding: quoted-printable\r\n\r\n")
	emailBuilder.WriteString(htmlEncoded.String())
	emailBuilder.WriteString("\r\n")

	// End boundary
	emailBuilder.WriteString(fmt.Sprintf("--%s--\r\n", boundary))

	return emailBuilder.String(), nil
}

