	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Escape HTML special characters in user input for safety
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedback := html.EscapeString(feedbackContent)

	// Format current time for Date header
	currentTime := time.Now().Format(time.RFC1123Z)

	// Encode subject for proper handling of special characters
	encodedSubject := mime.QEncoding.Encode("UTF-8", fmt.Sprintf("Feedback: %s", escapedSubject))

	// Construct email headers with proper formatting
	headers := []string{
