        </div>

        <div class="content">
            <div class="field">
                <div class="label">Username:</div>
                <div class="value">%s</div>
            </div>

            <div class="field">
                <div class="label">Feedback Subject:</div>
                <div class="value">%s</div>
            </div>

            <div class="field">
                <div class="label">Feedback Content:</div>
                <div class="feedback-content">%s</div>
            </div>
