func SendFeedbackEmail(smtpHost string, smtpPort int, smtpUsername, smtpPassword string, fromAddr string, toAddr string, userName string, subject string, feedbackContent string) error {
	// Build the email body
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
