// BuildFeedbackEmail generates an HTML-formatted email containing user feedback
// Parameters:
//   - fromAddr: sender email address
//   - toAddr: recipient email address (customer support)
//   - userName: name of the user submitting feedback
//   - subject: feedback subject/title
//   - feedbackContent: detailed feedback content
//
// Returns:
//   - emailBody: complete email message ready for SMTP transmission
//   - err: error if any occurred during email construction
func BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent string) (emailBody string, err error) {
	// Validate required parameters
	if fromAddr == "" || toAddr == "" || userName == "" || subject == "" || feedbackContent == "" {
		return "", fmt.Errorf("all parameters must be non-empty")
	}

	// Generate unique message ID
	messageID := generateMessageID(fromAddr)

	// Current timestamp for email headers
	currentTime := time.Now().Format(time.RFC1123Z)

	// Encode subject for email headers (handles special characters)
	encodedSubject := mime.QEncoding.Encode("UTF-8", subject)

	// Build email headers
	headers := map[string]string{
		"From":                      fmt.Sprintf("Feedback System <%s>", fromAddr),
		"To":                        toAddr,
		"Subject":                   encodedSubject,
		"Message-ID":                messageID,
		"Date":                      currentTime,
		"MIME-Version":              "1.0",
		"Content-Type":              "text/html; charset=UTF-8",
		"Content-Transfer-Encoding": "quoted-printable",
	}

	// Build HTML email body with user feedback
	htmlBody := buildHTMLBody(userName, subject, feedbackContent)

	// Encode HTML body using quoted-printable encoding
	var encodedBody bytes.Buffer
	writer := quotedprintable.NewWriter(&encodedBody)
	if _, err := writer.Write([]byte(htmlBody)); err != nil {
		return "", fmt.Errorf("failed to encode email body: %w", err)
	}
	if err := writer.Close(); err != nil {
		return "", fmt.Errorf("failed to close quoted-printable writer: %w", err)
	}

	// Combine headers and body into final email
	var emailBuffer bytes.Buffer

	// Write headers
	for key, value := range headers {
		emailBuffer.WriteString(fmt.Sprintf("%s: %s\r\n", key, value))
	}

	// Empty line separating headers and body
	emailBuffer.WriteString("\r\n")

	// Write encoded body
	emailBuffer.Write(encodedBody.Bytes())

	return emailBuffer.String(), nil
}

