package main

import (
	"fmt"
	"html"
	"mime"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (optional but good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Encode subject for email headers (handles non-ASCII characters)
	emailSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := mime.QEncoding.Encode("UTF-8", emailSubject)

	// Construct email headers
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		encodedSubject,
	)

	// Escape HTML special characters to prevent XSS
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedbackContent := html.EscapeString(feedbackContent)

	// Preserve line breaks in feedback content
	formattedFeedback := strings.ReplaceAll(escapedFeedbackContent, "\n", "<br>")

	// Construct HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
    .container { max-width: 600px; margin: 0 auto; padding: 20px; }
    .header { background-color: #f8f9fa; padding: 15px; border-radius: 5px; margin-bottom: 20px; }
    .content { background-color: #fff; padding: 20px; border: 1px solid #dee2e6; border-radius: 5px; }
    .field { margin-bottom: 15px; }
    .field-label { font-weight: bold; color: #495057; margin-bottom: 5px; }
    .field-value { padding: 10px; background-color: #f9f9f9; border: 1px solid #e9ecef; border-radius: 3px; }
    .feedback-box { white-space: pre-wrap; font-family: monospace; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h2 style="margin: 0; color: #007bff;">📨 User Feedback Received</h2>
    </div>

    <div class="content">
      <div class="field">
        <div class="field-label">Submitted by:</div>
        <div class="field-value">%s</div>
      </div>

      <div class="field">
        <div class="field-label">Subject:</div>
        <div class="field-value">%s</div>
      </div>

      <div class="field">
        <div class="field-label">Feedback Message:</div>
        <div class="field-value feedback-box">%s</div>
      </div>
    </div>

    <div style="margin-top: 20px; padding-top: 15px; border-top: 1px solid #dee2e6; font-size: 12px; color: #6c757d;">
      <p>This email was automatically generated by the feedback system.</p>
    </div>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		formattedFeedback,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

