        <p>Please respond to this feedback within 48 hours.</p>
    </div>
</body>
</html>`

	// Insert data into HTML template
	htmlBody := fmt.Sprintf(htmlTemplate, currentTime, escapedUserName, escapedSubject, escapedContent)
	bodyBuffer.WriteString(htmlBody)
	bodyBuffer.WriteString("\r\n")

	// Close the boundary
	bodyBuffer.WriteString(fmt.Sprintf("--%s--\r\n", boundary))

	return bodyBuffer.String(), nil
}

// Helper function to send the email using SMTP
// This is provided as a utility but not required by the original function signature
func SendFeedbackEmail(smtpHost string, smtpPort int, smtpUsername, smtpPassword string, emailBody string) error {
	// SMTP server configuration
	smtpAddr := fmt.Sprintf("%s:%d", smtpHost, smtpPort)

	// Extract the "From" address from the email body
	lines := strings.Split(emailBody, "\r\n")
	var fromAddr string
	for _, line := range lines {
		if strings.HasPrefix(line, "From: ") {
			fromAddr = strings.TrimPrefix(line, "From: ")
			break
		}
	}

	if fromAddr == "" {
		return fmt.Errorf("could not extract sender address from email body")
	}

	// Extract the "To" address from the email body
	var toAddr string
	for _, line := range lines {
		if strings.HasPrefix(line, "To: ") {
			toAddr = strings.TrimPrefix(line, "To: ")
			break
		}
	}

	if toAddr == "" {
		return fmt.Errorf("could not extract recipient address from email body")
	}

	// Authenticate and send the email
	auth := smtp.PlainAuth("", smtpUsername, smtpPassword, smtpHost)
	return smtp.SendMail(smtpAddr, auth, fromAddr, []string{toAddr}, []byte(emailBody))
}

